// Handles both Sonarr and Radarr "On Import/Download" webhook payloads
const b = $json.body || $json;
let title = 'New media added';
let message = 'New media added to the library.';

if (b.movie) {                              // Radarr
  const y = b.movie.year ? ` (${b.movie.year})` : '';
  title = '🎬 New movie added';
  message = `🎬 ${b.movie.title}${y} is now available.`;
} else if (b.series) {                       // Sonarr
  const eps = (b.episodes || [])
    .map(e => `S${String(e.seasonNumber).padStart(2,'0')}E${String(e.episodeNumber).padStart(2,'0')} – ${e.title || ''}`)
    .join(', ');
  title = '📺 New episode added';
  message = `📺 ${b.series.title}${eps ? ' — ' + eps : ''} is now available.`;
}

return [{ json: { title, message, eventType: b.eventType || null, raw: b } }];
